CREATE TABLE public.category (
    uuid uuid NOT NULL PRIMARY KEY,
    id SMALLINT DEFAULT 0 NOT NULL,
    parent_id SMALLINT DEFAULT 0 NOT NULL,
    code VARCHAR(10) DEFAULT ''::VARCHAR NOT NULL,
    text VARCHAR(255) DEFAULT ''::VARCHAR NOT NULL,
    gws_group VARCHAR(8) DEFAULT ''::VARCHAR NOT NULL,
    destination SMALLINT DEFAULT 0 NOT NULL,
    is_automatized BOOLEAN DEFAULT false NOT NULL,
    is_non_assignable BOOLEAN DEFAULT false NOT NULL,
    is_removed BOOLEAN DEFAULT false NOT NULL,
    created_at TIMESTAMP WITHOUT TIME ZONE DEFAULT '1900-01-01 00:00:00'::TIMESTAMP WITHOUT TIME ZONE NOT NULL,
    created_by INTEGER DEFAULT 0 NOT NULL,
    changed_at TIMESTAMP WITHOUT TIME ZONE DEFAULT '1900-01-01 00:00:00'::TIMESTAMP WITHOUT TIME ZONE NOT NULL,
    changed_by INTEGER DEFAULT 0 NOT NULL
);

